		vmax = in.nextDouble();
		len = in.nextDouble();
		d = in.nextDouble();
		w = in.nextDouble();

		out.println(fmt.format(T()));
	}//end public void main()

	public double T()
	{
		double t, s;

		double t1, s1;
		t1 = vmax / a;
		s1 = vmax*vmax/(2.0*a);

		double t3, s3;
		t3 = w/a;
		s3 = w*w/(2.0*a);

		if(w >= vmax)
		{
			if(s1 < len)
			{
				return t1 + (len - s1)/vmax;
			}
			else
			{
				return Math.sqrt(2.0*len/a);
			}			
		}
		else
		{
			//w < vmax

			double t2, s2, v2;
			t2 = Math.sqrt(2.0*d/a);
			v2 = a*t2;

			double tx, vx;
			vx = Math.sqrt((2.0*a*d + w*w)/2.0);
			tx = vx / a;	

			//vmax > w

			//v2 > vx > w

			if(v2 < w)
			{
				if(v2 > vmax)
				{
					//v2 > vmax > w
					if(vmax > vx)
					{
						return tx + (vx - w)/a + T2(w);
					}
					else
					{
						double ty, sy;
						ty = (vmax - w)/a;
						sy = ty * (vmax + w)/2.0;
						return t1 + ty + (d - s1 - sy)/vmax + T2(w);
					}
				}
				else
				{
					//v2 < w, v2 <= vmax
