		n -= F2;
		int F3 = getClosest(n);

		out.println(F1 + " " + F2 + " " + F3);



		out.close();
	}

	// Gets the closest fibonacci number to n.
	public static int getClosest(int n) {
		int closest = 0;
		int f1 = 0;
		int f2 = 1;

		while (f1 <= n) {
			closest = Math.max(closest, f1);

			int next = f1 + f2;
			f1 = f2;
			f2 = next;
		}

		return closest;
	}
}

