			long c3 = (n-1)*(n-2)*(n-3);
			if(n%2==0)
				c1/=2;
			else
				c3/=2;
			if(n%3==0)
				c2/=3;
			long ans = Math.max(c1, c2);
			ans = Math.max(ans, c3);
			System.out.println(ans);
		}
	}
}

