		long b=Long.parseLong(st.nextToken());
		long sum = 0;
		while(a!= 0 && b!= 0){
			if (a > b){
				long val = a / b;
				sum += val;
				a -= val * b;
			}
			else{
				long val = b / a;
				sum += val;
				b -= val * a;
			}
		}

		out.println(sum);
		out.close();
		System.exit(0);
	}

}

