	// solution
	int choose(int total, int choose){
	    if(total < choose)
	        return 0;
	    if(choose == 0 || choose == total)
	        return 1;
	    return choose(total-1,choose-1)+choose(total-1,choose);
	}
	void solve() throws IOException {
		long l = readLong();
		long r = readLong();
		if(r-l>=3){
