    private void solve() throws Exception {
        int n = i(), p = i(), l = i(), r = i();
        int t = 0;

        if (r - l + 1 == n) {
            w(0);
            return;
        }

        if (p > r) {
            t += p - r;
            p = r;
        }
        if (p < l) {
            t += l - p;
            p = l;
        }

        if (l == 1) {
            t += r - p + 1;
        } else if (r == n) {
            t += p - l + 1;
        } else {
            t += min(r - p, p - l) + (r - l) + 2;
        }

        w(t);
    }

