        if (str1.length() < str2.length()) {
            return gcd(str2, str1);
        }

        // If str1 is not the
        // concatenation of str2
        else if (!str1.startsWith(str2)) {
            return "";
        }

        else if (str2.isEmpty()) {

            // GCD string is found
            return str1;
        }
        else {

            // Cut off the common prefix
