class Solution {
    public String whoIsWinner(long x, long y, long N) {
		if(x == 1 && y == 1) return "White";
		if(x == N && y == N) return "Black";
		return Math.max(N - x, N - y) < Math.max(x - 1, y - 1) ? "Black" : "White";
    }
}

