	private static long fc (long p, long q, boolean up) {
		if (up) {
			if (q < 0) return fc(-p, -q, true);
			else if (p < 0) return -fc(-p, q, false);
			else return (p+q-1) / q;
		}
		else if (q < 0) return fc(-p, -q, false);
		else if (p < 0) return -fc(-p, q, true);
