public class PetyaAndOrigami {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        int numFriends = scanner.nextInt();
        int numSheets = scanner.nextInt();
        System.out.println(numberOfNotebooks(numFriends, numSheets));

        scanner.close();
    }

    static int numberOfNotebooks(int numFriends, int numSheets) {
        return IntStream.of(2, 5, 8).map(n -> partition(n * numFriends, numSheets)).sum();
    }

    static int partition(int friends, int sheets) {
        return friends / sheets + (friends % sheets == 0 ? 0 : 1);
    }

}

